import{_ as t,C as n,o as r,c as d,j as i,a,E as o,a3 as l}from"./chunks/framework.D3_W51PR.js";const v=JSON.parse('{"title":"Update-Prüfung","description":"","frontmatter":{},"headers":[],"relativePath":"de/advanced/update-check.md","filePath":"de/advanced/update-check.md"}'),h={name:"de/advanced/update-check.md"},c={id:"update-prufung",tabindex:"-1"};function p(u,e,g,k,f,m){const s=n("VersionBadge");return r(),d("div",null,[i("h1",c,[e[0]||(e[0]=a("Update-Prüfung ",-1)),o(s,{v:"0.9.0"}),e[1]||(e[1]=a()),e[2]||(e[2]=i("a",{class:"header-anchor",href:"#update-prufung","aria-label":'Permalink to "Update-Prüfung <VersionBadge v="0.9.0" />"'},"​",-1))]),e[3]||(e[3]=l('<p>Wenn eine neuere amoxide-Version auf crates.io erscheint, sagt dir <code>am ls</code> beim nächsten Listing Bescheid. Der Hinweis geht auf stderr, die Prüfung läuft im Hintergrund, und du kannst sie abschalten.</p><h2 id="was-du-siehst" tabindex="-1">Was du siehst <a class="header-anchor" href="#was-du-siehst" aria-label="Permalink to &quot;Was du siehst&quot;">​</a></h2><p>Wenn du hinterher bist, geben die Listing-Befehle (<code>am ls</code>, <code>am la</code>, <code>am profile list</code>) eine Zeile auf stderr aus, nach der Liste:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>am: 💡 a new version is available: v0.9.0 -&gt; visit https://github.com/sassman/amoxide-rs/releases</span></span></code></pre></div><p>Wenn du aktuell bist, siehst du nichts.</p><h2 id="so-funktioniert-es" tabindex="-1">So funktioniert es <a class="header-anchor" href="#so-funktioniert-es" aria-label="Permalink to &quot;So funktioniert es&quot;">​</a></h2><ul><li>Beim ersten Listing-Aufruf startet amoxide einen abgekoppelten Hintergrundprozess, der crates.io anfragt. Die Liste erscheint sofort — du wartest nicht aufs Netzwerk.</li><li>Das Ergebnis landet in <code>~/.cache/amoxide/update-check.toml</code>.</li><li>Beim nächsten Listing liest amoxide diese Datei. Ist sie älter als 24 Stunden, läuft im Hintergrund eine neue Prüfung, und das vorherige Ergebnis (falls vorhanden) wird inzwischen angezeigt.</li><li>Netzwerkfehler bleiben stumm. Offline, DNS kaputt, crates.io down — die Liste funktioniert, nur der Hinweis erscheint nicht.</li></ul><p>Der Hinweis steht auf stderr, also bleiben Pipes unberührt:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mein-alias</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # der Hinweis fällt nicht in die Pipe</span></span></code></pre></div><h2 id="prufung-deaktivieren" tabindex="-1">Prüfung deaktivieren <a class="header-anchor" href="#prufung-deaktivieren" aria-label="Permalink to &quot;Prüfung deaktivieren&quot;">​</a></h2><p>Zwei Wege: ein Konfigurations-Flag (dauerhaft) oder eine Umgebungsvariable (einmalig, für CI).</p><h3 id="konfiguration-config-amoxide-config-toml" tabindex="-1">Konfiguration: <code>~/.config/amoxide/config.toml</code> <a class="header-anchor" href="#konfiguration-config-amoxide-config-toml" aria-label="Permalink to &quot;Konfiguration: `~/.config/amoxide/config.toml`&quot;">​</a></h3><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">update</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">check = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><p>Mit <code>check = false</code> gibt es kein Cache-Lesen, kein Spawn, keinen Netzwerkaufruf. Die Cache-Datei wird gar nicht erst angelegt.</p><h3 id="umgebung-am-no-update-check" tabindex="-1">Umgebung: <code>AM_NO_UPDATE_CHECK</code> <a class="header-anchor" href="#umgebung-am-no-update-check" aria-label="Permalink to &quot;Umgebung: `AM_NO_UPDATE_CHECK`&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">AM_NO_UPDATE_CHECK</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span></span></code></pre></div><p>Jeder nicht-leere Wert überspringt die Prüfung für diesen einen Aufruf. Praktisch in CI, wo du weder Netzwerkverkehr noch eine Konfigurationsdatei pflegen willst.</p><h2 id="datenschutz" tabindex="-1">Datenschutz <a class="header-anchor" href="#datenschutz" aria-label="Permalink to &quot;Datenschutz&quot;">​</a></h2><p>Ein HTTPS-GET an <code>https://crates.io/api/v1/crates/amoxide</code>. Mehr nicht — Crate-Name plus der Standard-User-Agent von ureq. Nichts identifiziert dich, nichts wird getrackt.</p><h2 id="siehe-auch" tabindex="-1">Siehe auch <a class="header-anchor" href="#siehe-auch" aria-label="Permalink to &quot;Siehe auch&quot;">​</a></h2><ul><li><a href="/_preview/128/de/advanced/config-files">Konfigurationsdateien</a> — vollständige TOML-Referenz</li></ul>',21))])}const C=t(h,[["render",p]]);export{v as __pageData,C as default};
